                while (iterator.hasNext()) {
                    var chatItem = iterator.next(); // This will be a V8.b object
                    console.log("  - Chat Item: " + chatItem.toString()); // Attempt to get string representation
                    // To get actual data, you'd need to know V8.b's methods/fields:
                    // var chatContent = chatItem.getChatContent();
                    // var senderId = chatItem.getSenderId();
                    // console.log(`    Content: ${chatContent}, Sender: ${senderId}`);
